@php
    declare(strict_types=1);
    // Привязка к сервису домена ConstructionMaterials
    $calculatorService = app(\App\Domains\ConstructionMaterials\Services\MaterialCalculatorService::class);
@endphp

<div x-data="{
    wallArea: 25,
    plasterType: 'Venetian',
    layers: 3,
    tooling: 'Spatula',
    protectiveLayer: true,
    installation: true,
    correlationId: '{{ Str::uuid() }}',
    
    // Данные из WoodFlow / Material-Core сервиса
    get serviceData() {
        return {
            'Venetian': { price: 1200, labor: 2500, consumption: 0.6 },
            'Travertine': { price: 900, labor: 1800, consumption: 1.2 },
            'Micro-concrete': { price: 1500, labor: 2200, consumption: 2.0 },
            'Silk': { price: 800, labor: 1200, consumption: 0.4 }
        }[this.plasterType];
    },
    
    get totalMaterial() {
        return Math.ceil(this.wallArea * this.serviceData.consumption * (this.layers / 2));
    },
    
    get totalPrice() {
        let matCost = this.totalMaterial * this.serviceData.price;
        let laborCost = this.installation ? (this.wallArea * this.serviceData.labor) : 0;
        let protectionCost = this.protectiveLayer ? (this.wallArea * 300) : 0;
        return Math.round(matCost + laborCost + protectionCost);
    },

    formatPrice(val) {
        return new Intl.NumberFormat('ru-RU', { style: 'currency', currency: 'RUB', maximumFractionDigits: 0 }).format(val);
    }
}" class="w-full bg-slate-950 rounded-[3rem] p-1 border border-white/5 shadow-2xl overflow-hidden group">
    
