            </div>

            <div class="flex-grow space-y-12 relative z-20 px-4 font-sans italic tracking-tighter leading-none italic tracking-tighter">
                <div class="space-y-6">
                    <div class="flex justify-between items-end mb-2 pr-2 leading-none font-sans italic tracking-tighter leading-none italic tracking-tighter">
                        <span class="text-[10px] text-slate-500 uppercase font-black tracking-widest block italic leading-none tracking-tighter font-sans italic tracking-tighter leading-none italic tracking-tighter">Surface Area (M²)</span>
                        <span class="text-3xl font-black text-white italic tracking-tighter leading-none italic font-sans italic tracking-tighter leading-none italic" x-text="wallArea"></span>
                    </div>
                    <div class="relative py-4">
                        <input type="range" x-model="wallArea" min="5" max="200" step="5" 
                               class="w-full h-1.5 bg-white/10 rounded-full appearance-none cursor-pointer accent-orange-600 transition-all font-sans italic tracking-tighter leading-none italic tracking-tighter">
                    </div>
                </div>

                <div class="grid grid-cols-2 gap-4 font-sans italic tracking-tighter leading-none italic">
                    <template x-for="type in ['Venetian', 'Travertine', 'Micro-concrete', 'Silk']">
                        <button @click="plasterType = type" 
                                class="py-5 rounded-2xl border font-black italic uppercase text-[10px] transition-all tracking-widest leading-none shadow-xl font-sans italic tracking-tighter leading-none italic"
                                :class="plasterType === type ? 'bg-orange-600 text-white border-orange-500 scale-[1.03]' : 'bg-white/5 text-slate-500 border-white/5 hover:bg-white/10 hover:text-white'">
                            <span x-text="type"></span>
                        </button>
                    </template>
                </div>

                <div class="grid grid-cols-1 gap-4 pt-4 border-t border-white/10 font-sans italic tracking-tighter leading-none italic tracking-tighter">
                    <div class="space-y-4 font-sans italic tracking-tighter leading-none italic tracking-tighter">
                        <div class="flex items-center justify-between p-6 bg-white/5 rounded-3xl border border-white/10 group hover:border-orange-500 transition-all font-sans italic tracking-tighter leading-none italic tracking-tighter">
                            <div class="text-left leading-none font-sans italic tracking-tighter leading-none italic tracking-tighter font-sans leading-none italic tracking-tighter font-sans leading-none italic tracking-tighter leading-none italic tracking-tighter">
                                <span class="text-lg font-black block text-white italic leading-none tracking-tighter">Protection Layer</span>
                                <span class="text-[9px] text-slate-500 uppercase font-black tracking-widest block mt-2 leading-none italic">Wax/Varnish finish</span>
                            </div>
                            <button @click="protectiveLayer = !protectiveLayer" class="w-14 h-7 rounded-full relative transition-all shadow-inner font-sans italic tracking-tighter leading-none italic tracking-tighter" :class="protectiveLayer ? 'bg-orange-600' : 'bg-white/10'">
                                <div class="absolute top-1 w-5 h-5 bg-white rounded-full transition-all shadow-md" :style="protectiveLayer ? 'inset-inline-start: 32px' : 'inset-inline-start: 4px'"></div>
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            <!-- Price Output -->
            <div class="mt-14 p-10 bg-white/5 rounded-[3.5rem] border border-white/10 backdrop-blur-3xl shadow-2xl overflow-hidden relative group/confirm transition-all font-sans italic tracking-tighter leading-none italic">
                <div class="absolute inset-x-0 h-[1px] bg-orange-500 top-0 opacity-40 italic tracking-tighter leading-none italic tracking-tighter"></div>
                <div class="flex items-center justify-between mb-8 relative z-20 leading-none font-sans italic tracking-tighter leading-none italic">
                    <div class="font-sans italic tracking-tighter leading-none italic tracking-tighter">
                        <span class="text-[12px] text-orange-500 uppercase font-black block tracking-[0.2em] mb-4 italic leading-none tracking-tighter font-sans leading-none italic tracking-tighter leading-none italic tracking-tighter font-sans leading-none italic tracking-tighter">Decorative Finish Budget</span>
                        <span class="text-6xl font-black text-white italic tracking-tighter leading-none shadow-xl font-sans italic tracking-tighter leading-none italic tracking-tighter leading-none font-sans italic tracking-tighter leading-none italic" x-text="formatPrice(totalPrice)"></span>
                    </div>
                </div>
                <button class="w-full bg-orange-600 hover:bg-orange-500 text-slate-950 font-black py-7 rounded-2xl transition-all shadow-2xl uppercase italic text-sm tracking-[0.2em] flex items-center justify-center space-x-5 active:scale-95 group/main relative overflow-hidden font-sans italic tracking-tighter leading-none italic">
                    <span class="relative z-10 italic tracking-tighter font-sans italic tracking-tighter leading-none italic">Execute Surface Rendering</span>
                    <svg xmlns="http://www.w3.org/2000/svg" class="h-6 w-6 relative z-10 transform group-hover/main:rotate-12 transition-transform font-sans italic tracking-tighter leading-none italic tracking-tighter" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="3" d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                </button>
            </div>
        </div>
    </div>
</div>
